#!/usr/bin/env python
"""
Quick test of CompositeFieldValidator functionality.
"""

import os
import sys
import django
from pathlib import Path

# Setup Django
os.environ.setdefault('DJANGO_SETTINGS_MODULE', 'tests.settings')
sys.path.insert(0, str(Path(__file__).parent))

django.setup()

from django import forms
from django.core.exceptions import ValidationError


# Test 1: Basic usage with working validation
def test_basic_validation():
    """Test basic composite validation."""

    def date_validation(start_date, end_date):
        """Validate that end_date is after start_date."""
        if start_date and end_date:
            return end_date > start_date
        return True

    class DateRangeForm(forms.Form):
        start_date = forms.DateField()
        end_date = forms.DateField()

        date_validator = forms.CompositeFieldValidator(
            validation_function=date_validation,
            field_names=['start_date', 'end_date'],
            message='End date must be after start date.'
        )

    # Valid data
    form = DateRangeForm({
        'start_date': '2024-01-01',
        'end_date': '2024-12-31'
    })

    if form.is_valid():
        print("✓ Test 1a passed: Valid date range accepted")
    else:
        print(f"✗ Test 1a failed: {form.errors}")

    # Invalid data
    form = DateRangeForm({
        'start_date': '2024-12-31',
        'end_date': '2024-01-01'
    })

    if not form.is_valid():
        print("✓ Test 1b passed: Invalid date range rejected")
    else:
        print("✗ Test 1b failed: Invalid data should not be valid")


# Test 2: Email confirmation validation
def test_email_confirmation():
    """Test email confirmation validation."""

    def email_match(email, email_confirm):
        """Validate that email and email_confirm match."""
        if email and email_confirm:
            return email == email_confirm
        return True

    class RegistrationForm(forms.Form):
        email = forms.EmailField()
        email_confirm = forms.EmailField()

        email_validator = forms.CompositeFieldValidator(
            validation_function=email_match,
            field_names=['email', 'email_confirm'],
            message='Email addresses do not match.'
        )

    # Matching emails
    form = RegistrationForm({
        'email': 'test@example.com',
        'email_confirm': 'test@example.com'
    })

    if form.is_valid():
        print("✓ Test 2a passed: Matching emails accepted")
    else:
        print(f"✗ Test 2a failed: {form.errors}")

    # Non-matching emails
    form = RegistrationForm({
        'email': 'test@example.com',
        'email_confirm': 'other@example.com'
    })

    if not form.is_valid():
        print("✓ Test 2b passed: Non-matching emails rejected")
    else:
        print("✗ Test 2b failed: Non-matching emails should not be valid")


# Test 3: Missing field handling
def test_missing_field_handling():
    """Test graceful handling of missing fields."""

    def validation_func(field1, field2):
        return field1 == field2

    class TestForm(forms.Form):
        field1 = forms.CharField(required=False)

        validator = forms.CompositeFieldValidator(
            validation_function=validation_func,
            field_names=['field1', 'nonexistent_field'],
            message='Fields must match.'
        )

    # Should not raise an error even though field2 doesn't exist
    form = TestForm({'field1': 'test'})

    # Form validation should handle this gracefully
    try:
        is_valid = form.is_valid()
        print("✓ Test 3 passed: Missing field handled gracefully")
    except Exception as e:
        print(f"✗ Test 3 failed: {e}")


# Test 4: Multiple validators
def test_multiple_validators():
    """Test multiple validators on same form."""

    def price_validation(regular_price, sale_price):
        if regular_price and sale_price:
            return sale_price < regular_price
        return True

    def discount_percentage_validation(regular_price, discount_percent):
        if regular_price and discount_percent is not None:
            return 0 < discount_percent < 100
        return True

    class ProductForm(forms.Form):
        regular_price = forms.DecimalField()
        sale_price = forms.DecimalField()
        discount_percent = forms.IntegerField()

        price_validator = forms.CompositeFieldValidator(
            validation_function=price_validation,
            field_names=['regular_price', 'sale_price'],
            message='Sale price must be less than regular price.'
        )

        discount_validator = forms.CompositeFieldValidator(
            validation_function=discount_percentage_validation,
            field_names=['regular_price', 'discount_percent'],
            message='Discount percent must be between 0 and 100.'
        )

    # Valid data
    form = ProductForm({
        'regular_price': '100.00',
        'sale_price': '80.00',
        'discount_percent': '20'
    })

    if form.is_valid():
        print("✓ Test 4a passed: Valid product pricing accepted")
    else:
        print(f"✗ Test 4a failed: {form.errors}")

    # Invalid discount
    form = ProductForm({
        'regular_price': '100.00',
        'sale_price': '80.00',
        'discount_percent': '150'
    })

    if not form.is_valid():
        print("✓ Test 4b passed: Invalid discount rejected")
    else:
        print("✗ Test 4b failed: Invalid discount should not be valid")


if __name__ == '__main__':
    print("Running CompositeFieldValidator tests...\n")
    test_basic_validation()
    print()
    test_email_confirmation()
    print()
    test_missing_field_handling()
    print()
    test_multiple_validators()
    print("\nAll tests completed!")

